import sys
g={'A':[('B',2),('C',5)],'B':[('C',1),('D',4)],'C':[('D',2)],'D':[]}
def shortest(v,target):
    if v==target:return 0
    best=float('inf')
    for u,w in g.get(v,[]):
        best=min(best,w+shortest(u,target))
    return best
print(shortest('A','D'))

